	function Test-UserCredentials
	{
		param (
			[System.Management.Automation.PSCredential]$Credential
		)
		
		if ($Credential.UserName -match "\\")
		{
			$Domain = ($Credential.UserName -split "\\")[0]
		}
		else
		{
			$Domain = $env:USERDOMAIN
		}
		
		$isValid = $false
		try
		{
			$PrincipalContext = New-Object System.DirectoryServices.AccountManagement.PrincipalContext([System.DirectoryServices.AccountManagement.ContextType]::Domain, $Domain)
			$isValid = $PrincipalContext.ValidateCredentials($Credential.UserName, $Credential.GetNetworkCredential().Password)
		}
		catch
		{
			Write-Host "An error occurred: $_"
		}
		finally
		{
			if ($PrincipalContext)
			{
				$PrincipalContext.Dispose()
			}
		}
		
		return $isValid
	}
	
