	$buttonSetUser_Click = {
		#TODO: Place custom script here
		$Error.clear()
		Add-Type -AssemblyName System.DirectoryServices.AccountManagement
		$script:setUserCredentials = Get-Credential -Message 'Set the credentials for Windows Authentication to your SCOM Data Warehouse Database' -ErrorAction Stop
		
		$result = Test-UserCredentials -Credential $script:setUserCredentials
		
		if ($result)
		{
			Write-Verbose "The user account is valid."
			$buttonStagingTables.Enabled = $true
			$buttonRunGroomingManually.Enabled = $true
			$DaysSelector.Enabled = $true
			$buttonResetToDefaults.Enabled = $true
		}
		else
		{
			Add-Type -AssemblyName PresentationCore, PresentationFramework
			$ButtonType = [System.Windows.MessageBoxButton]::OK
			$MessageIcon = [System.Windows.MessageBoxImage]::Error
			$MessageBody = "The user account is not valid or the password is incorrect."
			$MessageTitle = "Experienced error while switching to another user"
			$Result = [System.Windows.MessageBox]::Show($MessageBody, $MessageTitle, $ButtonType, $MessageIcon)
			$buttonStagingTables.Enabled = $false
			$buttonRunGroomingManually.Enabled = $false
			$DaysSelector.Enabled = $false
			$buttonResetToDefaults.Enabled = $false
		}
		
		if (-NOT $script:setUserCredentials)
		{
			Out-Null
		}
		else
		{
			$textboxCurrentUser.Text = $script:setUserCredentials.UserName
			$mainForm.Activate()
			$buttonRefreshDataTop_Click.Invoke()
			$buttonRefreshDataBottom_Click.Invoke()
		}
	}
	
