		#TODO: Place custom script here
		if ($_.KeyCode -eq 'F5')
		{
			$buttonRefreshGrooming_Click.Invoke()
		}
	}
	
	$buttonRefreshGrooming_KeyUp=[System.Windows.Forms.KeyEventHandler]{
	#Event Argument: $_ = [System.Windows.Forms.KeyEventArgs]
		#TODO: Place custom script here
		if ($_.KeyCode -eq 'F5')
		{
			$buttonRefreshGrooming_Click.Invoke()
		}
	}
	
